export default{
	data() {
		return {
			orderDetail:{
				order_id:''
			}
		}
	},
	onLoad(option) {
		this.cbo_id = option.cbo_id;
		if(this.cbo_id){
			this.getOrderDetail();
		}
	},
	methods:{
		getOrderDetail(){
			uni.showLoading({
				title:'正在加载数据...'
			})
			this.$api.getInfoOrderapi({order_id:this.cbo_id},res =>{
				if(res.code == 1000){
				  this.orderDetail = res.data;	
				}
			})
		},
		cancelOrder(){
			let _this = this;
			uni.showModal({
				title: '取消订单',
				content: '是否取消订单？',
				success(res) {
					if (res.confirm) {
						_this.$api.cancelOrderapi({order_id:_this.cbo_id},res =>{
							if(res.code == 1000){
								uni.showToast({
									icon:'none',
									title:'取消成功！'
								})
								setTimeout(() =>{
									_this.getOrderDetail();
								},1000)
							}
						})
					}
				}
			});
			
		}
	}
}
